( --- AETHER AUTO-GLOBALS --- )
VARIABLE CHANNELS_INITED
0 CHANNELS_INITED !
INIT_HEAP
VARIABLE LV_TEST_ARRAY_ARR
VARIABLE LV_TEST_ARRAY_V1
VARIABLE LV_TEST_ARRAY_V2
( ------------------------- )

: TEST_ARRAY
  ALLOC_CHUNK DUP LV_TEST_ARRAY_ARR !
  ALLOC_CHUNK OVER !
  DUP @ OVER 4 + !
  0 OVER 8 + !
  DROP
  10
  LV_TEST_ARRAY_ARR @
  ( -- DynamicArray PUSH -- )
  DUP 8 + @
  DUP 15 MOD 0= OVER 0> AND IF
    ALLOC_CHUNK
    OVER 4 + @ !
    ALLOC_CHUNK OVER 4 + !
    ALLOC_CHUNK
    2 PICK 4 + @ !
  ELSE
  THEN
  DUP 8 + @
  DUP 15 MOD 0= OVER 0> AND IF
    ALLOC_CHUNK
    DUP 3 PICK 4 + @ !
    2 PICK 4 + !
  THEN
  15 MOD 1+ CELLS
  OVER 4 + @ +
  ROT SWAP !
  1 SWAP 8 + +!
  20
  LV_TEST_ARRAY_ARR @
  ( -- DynamicArray PUSH -- )
  DUP 8 + @
  DUP 15 MOD 0= OVER 0> AND IF
    ALLOC_CHUNK
    OVER 4 + @ !
    ALLOC_CHUNK OVER 4 + !
    ALLOC_CHUNK
    2 PICK 4 + @ !
  ELSE
  THEN
  DUP 8 + @
  DUP 15 MOD 0= OVER 0> AND IF
    ALLOC_CHUNK
    DUP 3 PICK 4 + @ !
    2 PICK 4 + !
  THEN
  15 MOD 1+ CELLS
  OVER 4 + @ +
  ROT SWAP !
  1 SWAP 8 + +!
  30
  LV_TEST_ARRAY_ARR @
  ( -- DynamicArray PUSH -- )
  DUP 8 + @
  DUP 15 MOD 0= OVER 0> AND IF
    ALLOC_CHUNK
    DUP 3 PICK 4 + @ !
    2 PICK 4 + !
  THEN
  15 MOD 1+ CELLS
  OVER 4 + @ +
  ROT SWAP !
  1 SWAP 8 + +!
  ARR_POP
  LV_TEST_ARRAY_V1 !
  ARR_POP
  LV_TEST_ARRAY_V2 !
  LV_TEST_ARRAY_V1 @
  LV_TEST_ARRAY_V2 @
  +
  TEMP_VSO_BUFFER ! ( Save return value for GC )
  LV_TEST_ARRAY_ARR @ DUP 0> IF
    DUP @ SWAP 4 + @ FREE_CHUNKS
  ELSE DROP THEN
  TEMP_VSO_BUFFER @ ( Restore return value )
  EXIT
;

